USE master
GO

IF DB_ID('QLSV') IS NOT NULL
BEGIN
    DROP DATABASE QLSV
END
GO

CREATE DATABASE QLSV
GO

USE QLSV
GO

CREATE TABLE SinhVien(
    masv varchar(20) PRIMARY KEY,
    hotensv nvarchar(100),
    malop varchar(20),
    ngaysinh varchar(50),
    noisinh nvarchar(100),
    diachi nvarchar(200)
)
GO

